let currentPath = '/';

function getNode(path) {
  if (path === '/' || path === '') return filesystem['/'];
  const parts = path.split('/').filter(p => p);
  let node = filesystem['/'];
  for (const part of parts) {
    if (!node || !node.children || !node.children[part]) return null;
    node = node.children[part];
  }
  return node;
}

function renderFiles() {
  const node = getNode(currentPath);
  const list = document.getElementById('files-list');
  const pathInput = document.getElementById('files-path');
  pathInput.value = currentPath;
  list.innerHTML = '';

  if (!node || node.type !== 'dir') {
    list.innerHTML = '<div style="padding:20px;color:#888;">Not a directory</div>';
    return;
  }

  const entries = Object.entries(node.children).sort((a, b) => {
    if (a[1].type !== b[1].type) return a[1].type === 'dir' ? -1 : 1;
    return a[0].localeCompare(b[0]);
  });

  if (entries.length === 0) {
    list.innerHTML = '<div style="padding:20px;color:#888;text-align:center;">This folder is empty</div>';
    return;
  }

  for (const [name, child] of entries) {
    const item = document.createElement('div');
    item.className = 'fs-item';
    let icon = '📄';
    if (child.type === 'dir') icon = '📁';
    else if (name.endsWith('.txt') || name.endsWith('.md')) icon = '📃';
    else if (name.endsWith('.jpg') || name.endsWith('.png')) icon = '🖼️';
    else if (name.endsWith('.mp3')) icon = '🎵';
    else if (name.endsWith('.mp4')) icon = '🎬';
    else if (name.endsWith('.html')) icon = '🌐';
    else if (name.endsWith('.deb') || name.endsWith('.zip')) icon = '📦';
    else if (name.startsWith('.')) icon = '⚙️';

    item.innerHTML = `<span class="fs-icon">${icon}</span><span>${name}</span>`;
    item.addEventListener('dblclick', () => {
      if (child.type === 'dir') {
        currentPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
        renderFiles();
      } else {
        openNotepadWithContent(child.content || '', name);
      }
    });
    list.appendChild(item);
  }
}

document.getElementById('files-up').addEventListener('click', () => {
  if (currentPath === '/') return;
  const parts = currentPath.split('/').filter(p => p);
  parts.pop();
  currentPath = '/' + parts.join('/');
  renderFiles();
});

const STORAGE_KEY = 'ubuntu-notepad-v1';
let tabs = [];
let activeTabId = null;

function loadTabs() {
  try {
    const data = JSON.parse(localStorage.getItem(STORAGE_KEY));
    if (data && Array.isArray(data.tabs) && data.tabs.length > 0) {
      tabs = data.tabs;
      activeTabId = data.activeTabId || tabs[0].id;
      return;
    }
  } catch (e) {}
  createNewTab();
}

function saveTabs() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify({ tabs, activeTabId }));
}

function createNewTab(content, name) {
  const id = 'tab-' + Date.now() + '-' + Math.random().toString(36).slice(2, 7);
  const tab = { id, name: name || 'Untitled', content: content || '' };
  tabs.push(tab);
  activeTabId = id;
  saveTabs();
  renderTabs();
  renderEditor();
}

function renderTabs() {
  const tabsEl = document.getElementById('tabs');
  const newBtn = document.getElementById('new-tab');
  tabsEl.innerHTML = '';
  tabsEl.appendChild(newBtn);

  for (const tab of tabs) {
    const tabEl = document.createElement('div');
    tabEl.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
    tabEl.dataset.id = tab.id;

    const nameEl = document.createElement('span');
    nameEl.className = 'tab-name';
    nameEl.textContent = tab.name || 'Untitled';

    const closeBtn = document.createElement('button');
    closeBtn.className = 'tab-close';
    closeBtn.textContent = '×';
    closeBtn.title = 'Close tab';
    closeBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      closeTab(tab.id);
    });

    tabEl.appendChild(nameEl);
    tabEl.appendChild(closeBtn);
    tabEl.addEventListener('click', () => switchTab(tab.id));
    tabsEl.appendChild(tabEl);
  }
}

function switchTab(id) {
  if (id === activeTabId) return;
  const editor = document.getElementById('editor');
  const currentTab = tabs.find(t => t.id === activeTabId);
  if (currentTab) {
    currentTab.content = editor.value;
    updateTabName(currentTab);
  }
  activeTabId = id;
  saveTabs();
  renderTabs();
  renderEditor();
}

function closeTab(id) {
  const idx = tabs.findIndex(t => t.id === id);
  if (idx === -1) return;
  tabs.splice(idx, 1);
  if (activeTabId === id) {
    activeTabId = tabs.length > 0 ? tabs[Math.min(idx, tabs.length - 1)].id : null;
  }
  if (tabs.length === 0) {
    createNewTab();
    return;
  }
  saveTabs();
  renderTabs();
  renderEditor();
}

function updateTabName(tab) {
  const firstLine = (tab.content || '').split('\n')[0] || '';
  tab.name = firstLine.slice(0, 24).trim() || 'Untitled';
}

function renderEditor() {
  const editor = document.getElementById('editor');
  const tab = tabs.find(t => t.id === activeTabId);
  editor.value = tab ? tab.content : '';
}

document.getElementById('new-tab').addEventListener('click', () => {
  const editor = document.getElementById('editor');
  const currentTab = tabs.find(t => t.id === activeTabId);
  if (currentTab) {
    currentTab.content = editor.value;
    updateTabName(currentTab);
  }
  createNewTab();
});

document.getElementById('editor').addEventListener('input', (e) => {
  const tab = tabs.find(t => t.id === activeTabId);
  if (tab) {
    tab.content = e.target.value;
    updateTabName(tab);
    saveTabs();
    const tabEl = document.querySelector(`.tab[data-id="${tab.id}"] .tab-name`);
    if (tabEl) tabEl.textContent = tab.name;
  }
});

function openNotepadWithContent(content, filename) {
  showWindow('notepad-window', 'open-notepad');
  createNewTab(content, filename);
}

let topZ = 100;

function showWindow(winId, launcherId) {
  const win = document.getElementById(winId);
  const launcher = document.getElementById(launcherId);
  win.classList.remove('hidden');
  launcher.classList.add('active');
  bringToFront(win);
}

function hideWindow(winId, launcherId) {
  const win = document.getElementById(winId);
  const launcher = document.getElementById(launcherId);
  win.classList.add('hidden');
  launcher.classList.remove('active');
}

function bringToFront(win) {
  topZ++;
  win.style.zIndex = topZ;
}

function setupWindow(winId, launcherId) {
  const win = document.getElementById(winId);
  const launcher = document.getElementById(launcherId);
  const closeBtn = win.querySelector('.win-close');

  launcher.addEventListener('click', () => showWindow(winId, launcherId));
  closeBtn.addEventListener('click', () => hideWindow(winId, launcherId));

  win.addEventListener('mousedown', () => bringToFront(win));

  const titlebar = win.querySelector('.window-titlebar');
  let isDragging = false;
  let startX, startY, startLeft, startTop;

  titlebar.addEventListener('mousedown', (e) => {
    if (e.target.closest('.window-controls')) return;
    isDragging = true;
    const rect = win.getBoundingClientRect();
    startX = e.clientX;
    startY = e.clientY;
    startLeft = rect.left;
    startTop = rect.top;
    bringToFront(win);
    e.preventDefault();
  });

  document.addEventListener('mousemove', (e) => {
    if (!isDragging) return;
    const dx = e.clientX - startX;
    const dy = e.clientY - startY;
    let newLeft = startLeft + dx;
    let newTop = startTop + dy;
    newTop = Math.max(28, newTop);
    newLeft = Math.max(-win.offsetWidth + 100, newLeft);
    win.style.left = newLeft + 'px';
    win.style.top = newTop + 'px';
  });

